record.field:
# Gán quyền Student Request Manager cho user được chọn
manager_group = env.ref('student_request.group_student_request_manager')
user_group = env.ref('student_request.group_student_request_user')

assigned_users = []
already_assigned = []

for user in records:
    if user.active:
        # Gán quyền user cơ bản
        if user_group not in user.groups_id:
            user.write({'groups_id': [(4, user_group.id)]})

        # Gán quyền manager
        if manager_group not in user.groups_id:
            user.write({'groups_id': [(4, manager_group.id)]})
            assigned_users.append(user.name)
        else:
            already_assigned.append(user.name)

# Hiển thị thông báo
message = ""
if assigned_users:
    message += f"✅ Đã gán quyền cho: {', '.join(assigned_users)}\n"
if already_assigned:
    message += f"ℹ️ Đã có quyền: {', '.join(already_assigned)}"

if message:
    return {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Gán quyền thành công',
            'message': message,
            'type': 'success',
            'sticky': False,
        }
    }

# Gỡ quyền Student Request Manager cho user được chọn
manager_group = env.ref('student_request.group_student_request_manager')

removed_users = []
not_assigned = []

for user in records:
    if user.active and user.login != 'admin':  # Không gỡ quyền admin
        if manager_group in user.groups_id:
            user.write({'groups_id': [(3, manager_group.id)]})
            removed_users.append(user.name)
        else:
            not_assigned.append(user.name)

# Hiển thị thông báo
message = ""
if removed_users:
    message += f"✅ Đã gỡ quyền: {', '.join(removed_users)}\n"
if not_assigned:
    message += f"ℹ️ Chưa có quyền: {', '.join(not_assigned)}"

if message:
    return {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Gỡ quyền thành công',
            'message': message,
            'type': 'info',
            'sticky': False,
        }
    }
